    public Object parseCurrency(Object rawCurrency)
    {
        Object id = this.safeString(rawCurrency, 0);
        Object code = this.safeCurrencyCode(id);
        Object type = ((Helpers.isTrue(this.safeString(rawCurrency, 7)))) ? "fiat" : "crypto";
        Object precision = this.parseNumber(this.parsePrecision(this.safeString(rawCurrency, 5)));
        Object networks = new java.util.HashMap<String, Object>() {{}};
        Object networkId = this.safeString(rawCurrency, 9);
        Object networkCode = null;
        if (Helpers.isTrue(!Helpers.isEqual(networkId, null)))
        {
            networkCode = this.networkIdToCode(networkId, code);
            final Object finalNetworkId = networkId;
            final Object finalNetworkCode = networkCode;
            Helpers.addElementToObject(networks, networkCode, new java.util.HashMap<String, Object>() {{
    put( "info", rawCurrency );
    put( "id", finalNetworkId );
    put( "network", finalNetworkCode );
    put( "active", null );
    put( "deposit", null );
    put( "withdraw", null );
    put( "fee", null );
    put( "precision", precision );
    put( "limits", new java.util.HashMap<String, Object>() {{
        put( "deposit", new java.util.HashMap<String, Object>() {{
            put( "min", null );
            put( "max", null );
        }} );
        put( "withdraw", new java.util.HashMap<String, Object>() {{
            put( "min", null );
            put( "max", null );
        }} );
    }} );
}});
        }
        return this.safeCurrencyStructure(new java.util.HashMap<String, Object>() {{
            put( "info", rawCurrency );
            put( "id", id );
            put( "code", code );
            put( "name", GeminiCore.this.safeString(rawCurrency, 1) );
            put( "active", null );
            put( "deposit", null );
            put( "withdraw", null );
            put( "fee", null );
            put( "type", type );
            put( "precision", precision );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "deposit", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "withdraw", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
            }} );
            put( "networks", networks );
        }});
    }

    /**
     * @method
     * @name gemini#fetchMarkets
     * @description retrieves data on all markets for gemini
     * @see https://docs.gemini.com/rest-api/#symbols
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} an array of objects representing market data
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMarkets(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object method = this.safeValue(this.options, "fetchMarketsMethod", "fetch_markets_from_api");
            if (Helpers.isTrue(Helpers.isEqual(method, "fetch_markets_from_web")))
            {
                Object promises = new java.util.ArrayList<Object>(java.util.Arrays.asList());
                ((java.util.List<Object>)promises).add(this.fetchMarketsFromWeb(parameters)); // get usd markets
                ((java.util.List<Object>)promises).add(this.fetchUSDTMarkets(parameters)); // get usdt markets
                Object promisesResult = (Helpers.promiseAll(promises)).join();
                return this.arrayConcat(Helpers.GetValue(promisesResult, 0), Helpers.GetValue(promisesResult, 1));
            }
            return (this.fetchMarketsFromAPI(parameters)).join();
        });

    }

    public java.util.concurrent.CompletableFuture<Object> fetchMarketsFromWeb(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object data = (this.fetchWebEndpoint("fetchMarkets", "webGetRestApi", false, "<h1 id=\"symbols-and-minimums\">Symbols and minimums</h1>")).join();
            Object error = Helpers.add(this.id, " fetchMarketsFromWeb() the API doc HTML markup has changed, breaking the parser of order limits and precision info for markets.");
            Object tables = Helpers.split(data, "tbody>");
            Object numTables = Helpers.getArrayLength(tables);
            if (Helpers.isTrue(Helpers.isLessThan(numTables, 2)))
            {
                throw new NotSupported((String)error) ;
            }
            Object rows = Helpers.split(Helpers.GetValue(tables, 1), "\n<tr>\n"); // eslint-disable-line quotes
            Object numRows = Helpers.getArrayLength(rows);
            if (Helpers.isTrue(Helpers.isLessThan(numRows, 2)))
            {
                throw new NotSupported((String)error) ;
            }
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            // skip the first element (empty string)
            for (var i = 1; Helpers.isLessThan(i, numRows); i++)
            {
                Object row = Helpers.GetValue(rows, i);
                Object cells = Helpers.split(row, "</td>\n"); // eslint-disable-line quotes
                Object numCells = Helpers.getArrayLength(cells);
                if (Helpers.isTrue(Helpers.isLessThan(numCells, 5)))
                {
                    throw new NotSupported((String)error) ;
                }
                //     [
                //         '<td>btcusd', // currency
                //         '<td>0.00001 BTC (1e-5)', // min order size
                //         '<td>0.00000001 BTC (1e-8)', // tick size
                //         '<td>0.01 USD', // quote currency price increment
                //         '</tr>'
                //     ]
                Object marketId = Helpers.replace((String)Helpers.GetValue(cells, 0), (String)"<td>", (String)"");
                marketId = Helpers.replace((String)marketId, (String)"*", (String)"");
                // const base = this.safeCurrencyCode (baseId);
                Object minAmountString = Helpers.replace((String)Helpers.GetValue(cells, 1), (String)"<td>", (String)"");
                Object minAmountParts = Helpers.split(minAmountString, " ");
                Object minAmount = this.safeNumber(minAmountParts, 0);
                Object amountPrecisionString = Helpers.replace((String)Helpers.GetValue(cells, 2), (String)"<td>", (String)"");
                Object amountPrecisionParts = Helpers.split(amountPrecisionString, " ");
                Object idLength = Helpers.subtract(Helpers.getArrayLength(marketId), 0);
                Object startingIndex = Helpers.subtract(idLength, 3);
                Object pricePrecisionString = Helpers.replace((String)Helpers.GetValue(cells, 3), (String)"<td>", (String)"");
                Object pricePrecisionParts = Helpers.split(pricePrecisionString, " ");
                Object quoteId = this.safeStringLower(pricePrecisionParts, 1, Helpers.slice(marketId, startingIndex, idLength));
                Object baseId = this.safeStringLower(amountPrecisionParts, 1, Helpers.replace((String)marketId, (String)quoteId, (String)""));
                Object base = this.safeCurrencyCode(baseId);
                Object quote = this.safeCurrencyCode(quoteId);
    final Object finalMarketId = marketId;
                final Object finalBase = base;
                            ((java.util.List<Object>)result).add(new java.util.HashMap<String, Object>() {{
                    put( "id", finalMarketId );
                    put( "symbol", Helpers.add(Helpers.add(finalBase, "/"), quote) );
                    put( "base", finalBase );
                    put( "quote", quote );
                    put( "settle", null );
                    put( "baseId", baseId );
                    put( "quoteId", quoteId );
                    put( "settleId", null );
                    put( "type", "spot" );
                    put( "spot", true );
                    put( "margin", false );
                    put( "swap", false );
                    put( "future", false );
                    put( "option", false );
                    put( "active", null );
                    put( "contract", false );
                    put( "linear", null );
                    put( "inverse", null );
                    put( "contractSize", null );
                    put( "expiry", null );
                    put( "expiryDatetime", null );
                    put( "strike", null );
                    put( "optionType", null );
                    put( "precision", new java.util.HashMap<String, Object>() {{
                        put( "amount", GeminiCore.this.safeNumber(amountPrecisionParts, 0) );
                        put( "price", GeminiCore.this.safeNumber(pricePrecisionParts, 0) );
                    }} );
                    put( "limits", new java.util.HashMap<String, Object>() {{
                        put( "leverage", new java.util.HashMap<String, Object>() {{
                            put( "min", null );
                            put( "max", null );
                        }} );
                        put( "amount", new java.util.HashMap<String, Object>() {{
                            put( "min", minAmount );
                            put( "max", null );
                        }} );
                        put( "price", new java.util.HashMap<String, Object>() {{
                            put( "min", null );
                            put( "max", null );
                        }} );
                        put( "cost", new java.util.HashMap<String, Object>() {{
                            put( "min", null );
                            put( "max", null );
                        }} );
                    }} );
                    put( "created", null );
                    put( "info", row );
                }});
            }
            return result;
        });

    }

    public Object parseMarketActive(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "open", true );
            put( "closed", false );
            put( "cancel_only", true );
            put( "post_only", true );
            put( "limit_only", true );
        }};
        if (Helpers.isTrue(Helpers.isEqual(status, null)))
        {
            return true;  // as defaulted below
        }
        return this.safeBool(statuses, status, true);
    }

    public java.util.concurrent.CompletableFuture<Object> fetchUSDTMarkets(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            // these markets can't be scrapped and fetchMarketsFrom api does an extra call
            // to load market ids which we don't need here
            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.inOp(this.urls, "test")))
            {
                return new java.util.ArrayList<Object>(java.util.Arrays.asList());  // sandbox does not have usdt markets
            }
            Object fetchUsdtMarkets = this.safeValue(this.options, "fetchUsdtMarkets", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(fetchUsdtMarkets)); i++)
            {
                Object marketId = Helpers.GetValue(fetchUsdtMarkets, i);
                Object request = new java.util.HashMap<String, Object>() {{
                    put( "symbol", marketId );
                }};
                // don't use Promise.all here, for some reason the exchange can't handle it and crashes
                Object rawResponse = (this.publicGetV1SymbolsDetailsSymbol(this.extend(request, parameters))).join();
                ((java.util.List<Object>)result).add(this.parseMarket(rawResponse));
            }
            return result;
        });

    }

    public java.util.concurrent.CompletableFuture<Object> fetchMarketsFromAPI(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object marketIdsRaw = (this.publicGetV1Symbols(parameters)).join();
            //
            //     [
            //         "btcusd",
            //         "linkusd",
            //         ...
            //     ]
            //
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object options = this.safeDict(this.options, "fetchMarketsFromAPI", new java.util.HashMap<String, Object>() {{}});
            Object brokenPairs = this.safeList(this.options, "brokenPairs", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object marketIds = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marketIdsRaw)); i++)
            {
                if (!Helpers.isTrue(this.inArray(Helpers.GetValue(marketIdsRaw, i), brokenPairs)))
                {
                    ((java.util.List<Object>)marketIds).add(Helpers.GetValue(marketIdsRaw, i));
                }
            }
            if (Helpers.isTrue(this.safeBool(options, "fetchDetailsForAllSymbols", false)))
            {
                Object promises = new java.util.ArrayList<Object>(java.util.Arrays.asList());
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marketIds)); i++)
                {
                    Object marketId = Helpers.GetValue(marketIds, i);
                    Object request = new java.util.HashMap<String, Object>() {{
                        put( "symbol", marketId );
                    }};
                    ((java.util.List<Object>)promises).add(this.publicGetV1SymbolsDetailsSymbol(this.extend(request, parameters)));
                }
                Object responses = (Helpers.promiseAll(promises)).join();
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(responses)); i++)
                {
                    ((java.util.List<Object>)result).add(this.parseMarket(Helpers.GetValue(responses, i)));
                }
            } else
            {
                // use trading-pairs info, if it was fetched
                Object tradingPairs = this.safeList(this.options, "tradingPairs");
                if (Helpers.isTrue(!Helpers.isEqual(tradingPairs, null)))
                {
                    Object indexedTradingPairs = this.indexBy(tradingPairs, 0);
                    for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marketIds)); i++)
                    {
                        Object marketId = Helpers.GetValue(marketIds, i);
                        Object pairInfo = this.safeList(indexedTradingPairs, ((String)marketId).toUpperCase());
                        if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(pairInfo, null)) && !Helpers.isTrue(this.inArray(marketId, brokenPairs))))
                        {
                            ((java.util.List<Object>)result).add(this.parseMarket(pairInfo));
                        }
                    }
                } else
                {
                    for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marketIds)); i++)
                    {
                        if (!Helpers.isTrue(this.inArray(Helpers.GetValue(marketIds, i), brokenPairs)))
                        {
                            ((java.util.List<Object>)result).add(this.parseMarket(Helpers.GetValue(marketIds, i)));
                        }
                    }
                }
            }
            return result;
        });

    }

    public Object parseMarket(Object response)
    {
        //
        // response might be:
        //
        //     btcusd
        //
        // or
        //
        //     [
        //         'BTCUSD',   // symbol
        //         2,          // tick precision (priceTickDecimalPlaces)
        //         8,          // amount precision (quantityTickDecimalPlaces)
        //         '0.00001',  // quantityMinimum
        //         10,         // quantityRoundDecimalPlaces
        //         true        // minimumsAreInclusive
        //     ],
        //
        // or
        //
        //     {
        //         "symbol": "BTCUSD", // perpetuals have 'PERP' suffix, i.e. DOGEUSDPERP
        //         "base_currency": "BTC",
        //         "quote_currency": "USD",
        //         "tick_size": 1E-8,
        //         "quote_increment": 0.01,
        //         "min_order_size": "0.00001",
        //         "status": "open",
        //         "wrap_enabled": false
        //         "product_type": "swap", // only in perps
        //         "contract_type": "linear", // only in perps
        //         "contract_price_currency": "GUSD"
        //     }
        //
        Object marketId = null;
        Object baseId = null;
        Object quoteId = null;
        Object settleId = null;
        Object tickSize = null;
        Object amountPrecision = null;
        Object minSize = null;
        Object status = null;
        Object swap = false;
        Object contractSize = null;
        Object linear = null;
        Object inverse = null;
        Object isString = ((response instanceof String));
        Object isArray = (Helpers.isArray(response));
        if (Helpers.isTrue(!Helpers.isTrue(isString) && !Helpers.isTrue(isArray)))
        {
            marketId = this.safeStringLower(response, "symbol");
            amountPrecision = this.safeNumber(response, "tick_size"); // right, exchange has an imperfect naming and this turns out to be an amount-precision
            tickSize = this.safeNumber(response, "quote_increment"); // this is tick-size actually
            minSize = this.safeNumber(response, "min_order_size");
            status = this.parseMarketActive(this.safeString(response, "status"));
            baseId = this.safeString(response, "base_currency");
            quoteId = this.safeString(response, "quote_currency");
            settleId = this.safeString(response, "contract_price_currency");
        } else
        {
            // if no detailed API was called, then parse either string or array
            if (Helpers.isTrue(isString))
            {
                marketId = response;
            } else
            {
                marketId = this.safeStringLower(response, 0);
                tickSize = this.parseNumber(this.parsePrecision(this.safeString(response, 1))); // priceTickDecimalPlaces
                amountPrecision = this.parseNumber(this.parsePrecision(this.safeString(response, 2))); // quantityTickDecimalPlaces
                minSize = this.safeNumber(response, 3); // quantityMinimum
            }
            Object marketIdUpper = ((String)((String)marketId)).toUpperCase();
            Object isPerp = (Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(marketIdUpper, "PERP"), 0));
            Object marketIdWithoutPerp = Helpers.replace((String)marketIdUpper, (String)"PERP", (String)"");
            Object conflictingMarkets = this.safeDict(this.options, "conflictingMarkets", new java.util.HashMap<String, Object>() {{}});
            Object lowerCaseId = ((String)marketIdWithoutPerp).toLowerCase();
            if (Helpers.isTrue(Helpers.inOp(conflictingMarkets, lowerCaseId)))
            {
                Object conflictingMarket = Helpers.GetValue(conflictingMarkets, lowerCaseId);
                baseId = Helpers.GetValue(conflictingMarket, "base");
                quoteId = Helpers.GetValue(conflictingMarket, "quote");
                if (Helpers.isTrue(isPerp))
                {
                    settleId = Helpers.GetValue(conflictingMarket, "quote");
                }
            } else
            {
                Object quoteCurrencies = this.handleOption("fetchMarketsFromAPI", "quoteCurrencies", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(quoteCurrencies)); i++)
                {
                    Object quoteCurrency = Helpers.GetValue(quoteCurrencies, i);
                    if (Helpers.isTrue(((String)marketIdWithoutPerp).endsWith(((String)quoteCurrency))))
                    {
                        Object quoteLength = this.parseToInt(Helpers.multiply(Helpers.opNeg(1), Helpers.getArrayLength(quoteCurrency)));
                        baseId = Helpers.slice(marketIdWithoutPerp, 0, quoteLength);
                        quoteId = quoteCurrency;
                        if (Helpers.isTrue(isPerp))
                        {
                            settleId = quoteCurrency; // always same
                        }
                        break;
                    }
                }
            }
        }
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        Object settle = this.safeCurrencyCode(settleId);
        Object symbol = Helpers.add(Helpers.add(base, "/"), quote);
        if (Helpers.isTrue(!Helpers.isEqual(settleId, null)))
        {
            symbol = Helpers.add(Helpers.add(symbol, ":"), settle);
            swap = true;
            contractSize = tickSize; // always same
            linear = true; // always linear
            inverse = false;
        }
        Object type = ((Helpers.isTrue(swap))) ? "swap" : "spot";
        Object isSpot = !Helpers.isTrue(swap);
        final Object finalMarketId = marketId;
        final Object finalSymbol = symbol;
        final Object finalBase = base;
        final Object finalBaseId = baseId;
        final Object finalQuoteId = quoteId;
        final Object finalSettleId = settleId;
        final Object finalSwap = swap;
        final Object finalStatus = status;
        final Object finalLinear = linear;
        final Object finalInverse = inverse;
        final Object finalContractSize = contractSize;
        final Object finalTickSize = tickSize;
        final Object finalAmountPrecision = amountPrecision;
        final Object finalMinSize = minSize;
        return new java.util.HashMap<String, Object>() {{
            put( "id", finalMarketId );
            put( "symbol", finalSymbol );
            put( "base", finalBase );
            put( "quote", quote );
            put( "settle", settle );
            put( "baseId", finalBaseId );
            put( "quoteId", finalQuoteId );
            put( "settleId", finalSettleId );
            put( "type", type );
            put( "spot", isSpot );
            put( "margin", false );
            put( "swap", finalSwap );
            put( "future", false );
            put( "option", false );
            put( "active", finalStatus );
            put( "contract", finalSwap );
            put( "linear", finalLinear );
            put( "inverse", finalInverse );
            put( "contractSize", finalContractSize );
            put( "expiry", null );
            put( "expiryDatetime", null );
            put( "strike", null );
            put( "optionType", null );
            put( "precision", new java.util.HashMap<String, Object>() {{
                put( "price", finalTickSize );
                put( "amount", finalAmountPrecision );
            }} );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "leverage", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", finalMinSize );
                    put( "max", null );
                }} );
                put( "price", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "cost", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
            }} );
            put( "created", null );
            put( "info", response );
        }};
    }

    /**
     * @method
     * @name gemini#fetchOrderBook
     * @description fetches information on open orders with bid (buy) and ask (sell) prices, volumes and other data
     * @see https://docs.gemini.com/rest-api/#current-order-book
     * @param {string} symbol unified symbol of the market to fetch the order book for
     * @param {int} [limit] the maximum amount of order book entries to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} A dictionary of [order book structures]{@link https://docs.ccxt.com/?id=order-book-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOrderBook(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object limit = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit_bids", limit);
                Helpers.addElementToObject(request, "limit_asks", limit);
            }
            Object response = (this.publicGetV1BookSymbol(this.extend(request, parameters))).join();
            return this.parseOrderBook(response, Helpers.GetValue(market, "symbol"), null, "bids", "asks", "price", "amount");
        });

    }

