            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object response = (this.publicGetV1Pricefeed(parameters)).join();
            //
            //     [
            //         {
            //             "pair": "BATUSD",
            //             "price": "0.20687",
