    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // public fetchTrades
        //
        //     {
        //         "timestamp":1601617445,
        //         "timestampms":1601617445144,
        //         "tid":14122489752,
        //         "price":"0.46476",
        //         "amount":"28.407209",
        //         "exchange":"gemini",
        //         "type":"buy"
        //     }
        //
        // private fetchTrades
        //
        //      {
        //          "price":"3900.00",
        //          "amount":"0.00996",
        //          "timestamp":1638891173,
        //          "timestampms":1638891173518,
        //          "type":"Sell",
        //          "aggressor":false,
        //          "fee_currency":"EUR",
        //          "fee_amount":"0.00",
        //          "tid":73621746145,
        //          "order_id":"73621746059",
        //          "exchange":"gemini",
        //          "is_auction_fill":false,
        //          "is_clearing_fill":false,
        //          "symbol":"ETHEUR",
        //          "client_order_id":"1638891171610"
        //      }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(trade, "timestampms");
        Object id = this.safeString(trade, "tid");
        Object orderId = this.safeString(trade, "order_id");
        Object feeCurrencyId = this.safeString(trade, "fee_currency");
        Object feeCurrencyCode = this.safeCurrencyCode(feeCurrencyId);
        Object fee = new java.util.HashMap<String, Object>() {{
            put( "cost", GeminiCore.this.safeString(trade, "fee_amount") );
            put( "currency", feeCurrencyCode );
        }};
        Object priceString = this.safeString(trade, "price");
        Object amountString = this.safeString(trade, "amount");
        Object side = this.safeStringLower(trade, "type");
        Object symbol = this.safeSymbol(null, market);
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "order", orderId );
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", GeminiCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "type", null );
            put( "side", side );
            put( "takerOrMaker", null );
            put( "price", priceString );
            put( "cost", null );
            put( "amount", amountString );
            put( "fee", fee );
        }}, market);
    }

    /**
     * @method
     * @name gemini#fetchTrades
     * @description get the list of most recent trades for a particular symbol
     * @see https://docs.gemini.com/rest-api/#trade-history
     * @param {string} symbol unified symbol of the market to fetch trades for
     * @param {int} [since] timestamp in ms of the earliest trade to fetch
     * @param {int} [limit] the maximum amount of trades to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=public-trades}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTrades(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object since = Helpers.getArg(optionalArgs, 0, null);
            Object limit = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit_trades", Helpers.mathMin(limit, 500));
            }
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "timestamp", since);
            }
            Object response = (this.publicGetV1TradesSymbol(this.extend(request, parameters))).join();
            //
            //     [
            //         {
            //             "timestamp":1601617445,
            //             "timestampms":1601617445144,
            //             "tid":14122489752,
            //             "price":"0.46476",
            //             "amount":"28.407209",
            //             "exchange":"gemini",
            //             "type":"buy"
            //         },
            //     ]
            //
            return this.parseTrades(response, market, since, limit);
        });

    }

    public Object parseBalance(Object response)
    {
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", response );
        }};
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(response)); i++)
        {
            Object balance = Helpers.GetValue(response, i);
            Object currencyId = this.safeString(balance, "currency");
            Object code = this.safeCurrencyCode(currencyId);
            Object account = this.account();
            Helpers.addElementToObject(account, "free", this.safeString(balance, "available"));
            Helpers.addElementToObject(account, "total", this.safeString(balance, "amount"));
            Helpers.addElementToObject(result, code, account);
        }
        return this.safeBalance(result);
    }

