    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // createOrder (private)
        //
        //      {
        //          "order_id":"106027397702",
        //          "id":"106027397702",
        //          "symbol":"etheur",
        //          "exchange":"gemini",
        //          "avg_execution_price":"2877.48",
        //          "side":"sell",
        //          "type":"exchange limit",
        //          "timestamp":"1650398122",
        //          "timestampms":1650398122308,
        //          "is_live":false,
        //          "is_cancelled":false,
        //          "is_hidden":false,
        //          "was_forced":false,
        //          "executed_amount":"0.014434",
        //          "client_order_id":"1650398121695",
        //          "options":[],
        //          "price":"2800.00",
        //          "original_amount":"0.014434",
        //          "remaining_amount":"0"
        //      }
        //
        // fetchOrder (private)
        //
        //      {
        //          "order_id":"106028543717",
        //          "id":"106028543717",
        //          "symbol":"etheur",
        //          "exchange":"gemini",
        //          "avg_execution_price":"0.00",
        //          "side":"buy",
        //          "type":"exchange limit",
        //          "timestamp":"1650398446",
        //          "timestampms":1650398446375,
        //          "is_live":true,
        //          "is_cancelled":false,
        //          "is_hidden":false,
        //          "was_forced":false,
        //          "executed_amount":"0",
        //          "client_order_id":"1650398445709",
        //          "options":[],
        //          "price":"2000.00",
        //          "original_amount":"0.01",
        //          "remaining_amount":"0.01"
        //      }
        //
        // fetchOpenOrders (private)
        //
        //      {
        //          "order_id":"106028543717",
        //          "id":"106028543717",
        //          "symbol":"etheur",
        //          "exchange":"gemini",
        //          "avg_execution_price":"0.00",
        //          "side":"buy",
        //          "type":"exchange limit",
        //          "timestamp":"1650398446",
        //          "timestampms":1650398446375,
        //          "is_live":true,
        //          "is_cancelled":false,
        //          "is_hidden":false,
        //          "was_forced":false,
        //          "executed_amount":"0",
        //          "client_order_id":"1650398445709",
        //          "options":[],
        //          "price":"2000.00",
        //          "original_amount":"0.01",
        //          "remaining_amount":"0.01"
        //      }
        //
        // cancelOrder (private)
        //
        //      {
        //          "order_id":"106028543717",
        //          "id":"106028543717",
        //          "symbol":"etheur",
        //          "exchange":"gemini",
        //          "avg_execution_price":"0.00",
        //          "side":"buy",
        //          "type":"exchange limit",
        //          "timestamp":"1650398446",
        //          "timestampms":1650398446375,
        //          "is_live":false,
        //          "is_cancelled":true,
        //          "is_hidden":false,
        //          "was_forced":false,
        //          "executed_amount":"0",
        //          "client_order_id":"1650398445709",
        //          "reason":"Requested",
        //          "options":[],
        //          "price":"2000.00",
        //          "original_amount":"0.01",
        //          "remaining_amount":"0.01"
        //      }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(order, "timestampms");
        Object amount = this.safeString(order, "original_amount");
        Object remaining = this.safeString(order, "remaining_amount");
        Object filled = this.safeString(order, "executed_amount");
        Object status = "closed";
        if (Helpers.isTrue(Helpers.GetValue(order, "is_live")))
        {
            status = "open";
        }
        if (Helpers.isTrue(Helpers.GetValue(order, "is_cancelled")))
        {
            status = "canceled";
        }
        Object price = this.safeString(order, "price");
        Object average = this.safeString(order, "avg_execution_price");
        Object type = this.safeString(order, "type");
        if (Helpers.isTrue(Helpers.isEqual(type, "exchange limit")))
        {
            type = "limit";
        } else if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(type, "market buy")) || Helpers.isTrue(Helpers.isEqual(type, "market sell"))))
        {
            type = "market";
        } else
        {
            type = Helpers.GetValue(order, "type");
        }
        Object fee = null;
        Object marketId = this.safeString(order, "symbol");
        Object symbol = this.safeSymbol(marketId, market);
        Object id = this.safeString(order, "order_id");
        Object side = this.safeStringLower(order, "side");
        Object clientOrderId = this.safeString(order, "client_order_id");
        Object optionsArray = this.safeValue(order, "options", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object option = this.safeString(optionsArray, 0);
        Object timeInForce = "GTC";
        Object postOnly = false;
        if (Helpers.isTrue(!Helpers.isEqual(option, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(option, "immediate-or-cancel")))
            {
                timeInForce = "IOC";
            } else if (Helpers.isTrue(Helpers.isEqual(option, "fill-or-kill")))
            {
                timeInForce = "FOK";
            } else if (Helpers.isTrue(Helpers.isEqual(option, "maker-or-cancel")))
            {
                timeInForce = "PO";
                postOnly = true;
            }
        }
        final Object finalStatus = status;
        final Object finalType = type;
        final Object finalTimeInForce = timeInForce;
        final Object finalPostOnly = postOnly;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "clientOrderId", clientOrderId );
            put( "info", order );
            put( "timestamp", timestamp );
            put( "datetime", GeminiCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "status", finalStatus );
            put( "symbol", symbol );
            put( "type", finalType );
            put( "timeInForce", finalTimeInForce );
            put( "postOnly", finalPostOnly );
            put( "side", side );
            put( "price", price );
            put( "triggerPrice", null );
            put( "average", average );
            put( "cost", null );
            put( "amount", amount );
            put( "filled", filled );
            put( "remaining", remaining );
            put( "fee", fee );
            put( "trades", null );
        }}, market);
    }

