    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // withdraw
        //
        //   for BTC
        //     {
        //         "address":"mi98Z9brJ3TgaKsmvXatuRahbFRUFKRUdR",
        //         "amount":"1",
        //         "withdrawalId":"02176a83-a6b1-4202-9b85-1c1c92dd25c4",
        //         "message":"You have requested a transfer of 1 BTC to mi98Z9brJ3TgaKsmvXatuRahbFRUFKRUdR. This withdrawal will be sent to the blockchain within the next 60 seconds."
        //     }
        //
        //   for ETH
        //     {
        //         "address":"0xA63123350Acc8F5ee1b1fBd1A6717135e82dBd28",
        //         "amount":"2.34567",
        //         "txHash":"0x28267179f92926d85c5516bqc063b2631935573d8915258e95d9572eedcc8cc"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(transaction, "timestampms");
        Object currencyId = this.safeString(transaction, "currency");
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object address = this.safeString(transaction, "destination");
        Object type = this.safeStringLower(transaction, "type");
        // if status field is available, then it's complete
        Object statusRaw = this.safeString(transaction, "status");
        Object fee = null;
        Object feeAmount = this.safeNumber(transaction, "feeAmount");
        if (Helpers.isTrue(!Helpers.isEqual(feeAmount, null)))
        {
            final Object finalFeeAmount = feeAmount;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeAmount );
                put( "currency", code );
            }};
        }
        final Object finalFee = fee;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", GeminiCore.this.safeString2(transaction, "eid", "withdrawalId") );
            put( "txid", GeminiCore.this.safeString(transaction, "txHash") );
            put( "timestamp", timestamp );
            put( "datetime", GeminiCore.this.iso8601(timestamp) );
            put( "network", null );
            put( "address", address );
            put( "addressTo", null );
            put( "addressFrom", null );
            put( "tag", null );
            put( "tagTo", null );
            put( "tagFrom", null );
            put( "type", type );
            put( "amount", GeminiCore.this.safeNumber(transaction, "amount") );
            put( "currency", code );
            put( "status", GeminiCore.this.parseTransactionStatus(statusRaw) );
            put( "updated", null );
            put( "internal", null );
            put( "comment", GeminiCore.this.safeString(transaction, "message") );
            put( "fee", finalFee );
        }};
    }

