    public Object sign(Object path, Object... optionalArgs)
    {
        Object api = Helpers.getArg(optionalArgs, 0, "public");
        Object method = Helpers.getArg(optionalArgs, 1, "GET");
        Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
        Object headers = Helpers.getArg(optionalArgs, 3, null);
        Object body = Helpers.getArg(optionalArgs, 4, null);
        Object url = Helpers.add("/", this.implodeParams(path, parameters));
        Object query = this.omit(parameters, this.extractParams(path));
        if (Helpers.isTrue(Helpers.isEqual(api, "private")))
        {
            this.checkRequiredCredentials();
            Object apiKey = this.apiKey;
            if (Helpers.isTrue(Helpers.isLessThan(Helpers.getIndexOf(apiKey, "account"), 0)))
            {
                throw new AuthenticationError((String)Helpers.add(this.id, " sign() requires an account-key, master-keys are not-supported")) ;
            }
            Object nonce = String.valueOf(this.nonce());
            Object finalUrl = url;
            Object request = this.extend(new java.util.HashMap<String, Object>() {{
                put( "request", finalUrl );
                put( "nonce", nonce );
            }}, query);
            Object payload = this.json(request);
            payload = this.stringToBase64(payload);
            Object signature = this.hmac(this.encode(payload), this.encode(this.secret), sha384());
            final Object finalPayload = payload;
            headers = new java.util.HashMap<String, Object>() {{
                put( "Content-Type", "text/plain" );
                put( "X-GEMINI-APIKEY", GeminiCore.this.apiKey );
                put( "X-GEMINI-PAYLOAD", finalPayload );
                put( "X-GEMINI-SIGNATURE", signature );
            }};
        } else
        {
            if (Helpers.isTrue(Helpers.getArrayLength(Helpers.objectKeys(query))))
            {
                url = Helpers.add(url, Helpers.add("?", this.urlencode(query)));
            }
        }
        url = Helpers.add(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), api), url);
        if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(method, "POST"))) || Helpers.isTrue((Helpers.isEqual(method, "DELETE")))))
        {
            body = this.json(query);
        }
        final Object finalUrl = url;
        final Object finalMethod = method;
        final Object finalBody = body;
        final Object finalHeaders = headers;
        return new java.util.HashMap<String, Object>() {{
            put( "url", finalUrl );
            put( "method", finalMethod );
            put( "body", finalBody );
            put( "headers", finalHeaders );
        }};
    }

    public Object handleErrors(Object httpCode, Object reason, Object url, Object method, Object headers, Object body, Object response, Object requestHeaders, Object requestBody)
    {
        if (Helpers.isTrue(Helpers.isEqual(response, null)))
        {
            if (Helpers.isTrue((body instanceof String)))
            {
                Object feedback = Helpers.add(Helpers.add(this.id, " "), body);
                this.throwBroadlyMatchedException(Helpers.GetValue(this.exceptions, "broad"), body, feedback);
            }
            return null;  // fallback to default error handler
        }
        //
        //     {
        //         "result": "error",
        //         "reason": "BadNonce",
        //         "message": "Out-of-sequence nonce <1234> precedes previously used nonce <2345>"
        //     }
        //
        Object result = this.safeString(response, "result");
        if (Helpers.isTrue(Helpers.isEqual(result, "error")))
        {
            Object reasonInner = this.safeString(response, "reason");
            Object message = this.safeString(response, "message");
            Object feedback = Helpers.add(Helpers.add(this.id, " "), message);
            this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), reasonInner, feedback);
            this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), message, feedback);
            this.throwBroadlyMatchedException(Helpers.GetValue(this.exceptions, "broad"), message, feedback);
            throw new ExchangeError((String)feedback) ;
        }
        return null;
    }

    /**
     * @method
     * @name gemini#createDepositAddress
     * @description create a currency deposit address
     * @see https://docs.gemini.com/rest-api/#new-deposit-address
     * @param {string} code unified currency code of the currency for the deposit address
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [address structure]{@link https://docs.ccxt.com/?id=address-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createDepositAddress(Object code, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object currency = this.currency(code);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "currency", Helpers.GetValue(currency, "id") );
            }};
            Object response = (this.privatePostV1DepositCurrencyNewAddress(this.extend(request, parameters))).join();
            Object address = this.safeString(response, "address");
            this.checkAddress(address);
            return new java.util.HashMap<String, Object>() {{
                put( "currency", code );
                put( "address", address );
                put( "tag", null );
                put( "network", null );
                put( "info", response );
            }};
        });

    }

    /**
     * @method
     * @name gemini#fetchOHLCV
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @see https://docs.gemini.com/rest-api/#candles
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object timeframeId = this.safeString(this.timeframes, timeframe, timeframe);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "timeframe", timeframeId );
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            Object response = (this.publicGetV2CandlesSymbolTimeframe(this.extend(request, parameters))).join();
            //
            //     [
            //         [1591515000000,0.02509,0.02509,0.02509,0.02509,0],
            //         [1591514700000,0.02503,0.02509,0.02503,0.02509,44.6405],
            //         [1591514400000,0.02503,0.02503,0.02503,0.02503,0],
            //     ]
            //
            return this.parseOHLCVs(response, market, timeframe, since, limit);
        });

    }

    /**
     * @method
     * @name gemini#fetchOpenInterest
     * @description retrieves the open interest of a contract trading pair
     * @see https://docs.gemini.com/rest/derivatives#get-risk-stats
     * @param {string} symbol unified CCXT market symbol
     * @param {object} [params] exchange specific parameters
     * @returns {object} an open interest structure{@link https://docs.ccxt.com/?id=open-interest-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOpenInterest(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            Object response = (this.publicGetV1RiskstatsSymbol(this.extend(request, parameters))).join();
            //
            //    {
            //        product_type: 'PerpetualSwapContract',
            //        mark_price: '9.023',
            //        index_price: '9.02072',
            //        open_interest: '4681.9',
            //        open_interest_notional: '42244.7837'
            //    }
            //
            return this.parseOpenInterest(response, market);
        });

    }

    public Object parseOpenInterest(Object interest, Object... optionalArgs)
    {
        //
        //    {
        //        product_type: 'PerpetualSwapContract',
        //        mark_price: '9.023',
        //        index_price: '9.02072',
        //        open_interest: '4681.9',
        //        open_interest_notional: '42244.7837'
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        return this.safeOpenInterest(new java.util.HashMap<String, Object>() {{
            put( "info", interest );
            put( "symbol", GeminiCore.this.safeString(market, "symbol") );
            put( "openInterestAmount", GeminiCore.this.safeString(interest, "open_interest") );
            put( "openInterestValue", GeminiCore.this.safeString(interest, "open_interest_notional") );
            put( "timestamp", null );
            put( "datetime", null );
        }}, market);
    }
